const raw = $input.first();
const content = raw.json.choices?.[0]?.message?.content || '{}';

let selected;
try {
  selected = JSON.parse(content);
} catch(e) {
  const match = content.match(/{[\s\S]*}/);
  selected = match ? JSON.parse(match[0]) : {};
}

const articulos = JSON.parse($('Agregar Noticias').first().json.articulos_json || '[]');
const matched = articulos.find(a => a.hash_titulo === selected.hash_titulo || a.titulo === selected.titulo) || {};

const score = parseFloat(selected.score_relevancia || 0);

return [{ json: {
  titulo: selected.titulo || matched.titulo || '',
  url: selected.url || matched.url || '',
  descripcion: matched.descripcion || '',
  pubDate: matched.pubDate || '',
  hash_titulo: selected.hash_titulo || matched.hash_titulo || '',
  score_relevancia: score,
  razon_seleccion: selected.razon || '',
  continuar: score >= 7
}}];

const raw = $input.first();
const content = raw.json.choices?.[0]?.message?.content || '{}';

let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  const match = content.match(/{[\s\S]*}/);
  parsed = match ? JSON.parse(match[0]) : {};
}

const article = $('Parsear Seleccion').first().json;
const fecha = new Date().toISOString().split('T')[0];

const TYPES    = ['hook','content','content','content','content','content','cta'];
const EMOJIS   = ['🤯','📰','💡','⚙️','✅','🔮','👇'];
const HEADLINES = ['¿Lo viste?','Qué pasó','Por qué te importa','Cómo funciona','En la práctica','El futuro que viene','¿Te gustó este contenido?'];
const BODIES    = ['','Noticia importante en el mundo de la IA.','Esto afecta tu trabajo y vida diaria.','Funciona de una forma que ya conoces.','Puedes usarlo en tu trabajo hoy mismo.','En 2-3 años esto será parte de tu rutina.','Síguenos para más noticias de IA cada semana.'];

let slides = parsed.slides || [];

while (slides.length < 7) {
  const i = slides.length;
  slides.push({ type: TYPES[i], headline: HEADLINES[i], body: BODIES[i], emoji_icon: EMOJIS[i] });
}

const enriched = slides.slice(0, 7).map((s, i) => ({
  num: i + 1,
  type: s.type || TYPES[i],
  headline: s.headline || HEADLINES[i],
  body: s.body || BODIES[i],
  emoji_icon: s.emoji_icon || EMOJIS[i],
  titulo_noticia: article.titulo || '',
  url_noticia: article.url || '',
  hash_titulo: article.hash_titulo || '',
  score: article.score_relevancia || 0,
  fecha: fecha
}));

return enriched.map(s => ({ json: s }));

const slide = $json;

// ⚠️ Reemplazar con UUIDs reales de https://placid.app
const TEMPLATE_UUIDS = {
  'hook':    'PLACID_TEMPLATE_HOOK',
  'content': 'PLACID_TEMPLATE_NORMAL',
  'cta':     'PLACID_TEMPLATE_CTA'
};

const type = slide.type || 'content';
const template_uuid = TEMPLATE_UUIDS[type] || TEMPLATE_UUIDS['content'];
const counter = String(slide.num).padStart(2, '0') + ' / 07';

const layers = {
  headline:      { text: slide.headline || '' },
  slide_counter: { text: counter },
  emoji_icon:    { text: slide.emoji_icon || '📌' }
};

// body solo para slides content y cta
if (type !== 'hook' && slide.body) {
  layers.body = { text: slide.body };
}

return [{ json: {
  ...slide,
  template_uuid,
  placid_layers: layers
}}];

const slideData = $('Preparar Placid Payload').item.json;
const checkResp = $json;

const imageUrl = checkResp.image_url || checkResp.url || '';
const renderId = checkResp.id || $('Placid - Crear Imagen').item.json?.id || '';

return [{ json: {
  num: slideData.num,
  type: slideData.type,
  headline: slideData.headline,
  body: slideData.body || '',
  emoji_icon: slideData.emoji_icon,
  titulo_noticia: slideData.titulo_noticia,
  url_noticia: slideData.url_noticia,
  hash_titulo: slideData.hash_titulo,
  score: slideData.score,
  fecha: slideData.fecha,
  image_url: imageUrl,
  placid_id: renderId,
  render_status: checkResp.status || 'unknown'
}}];

const slides = $input.all();
const first = slides[0]?.json || {};

const slidesData = slides
  .map(s => s.json)
  .sort((a, b) => (a.num || 0) - (b.num || 0));

const imageUrls = slidesData.map(s => s.image_url).filter(Boolean);

const slidesTexto = slidesData
  .map(s => s.num + '. [' + s.type + '] ' + s.headline + (s.body ? ': ' + s.body : ''))
  .join('\n');

return [{ json: {
  titulo_noticia: first.titulo_noticia || '',
  url_noticia: first.url_noticia || '',
  hash_titulo: first.hash_titulo || '',
  score: first.score || 0,
  fecha: first.fecha || new Date().toISOString().split('T')[0],
  slides_data: slidesData,
  slides_texto: slidesTexto,
  image_urls: imageUrls,
  image_urls_str: imageUrls.join('\n'),
  total_slides: slidesData.length,
  slides_con_imagen: imageUrls.length
}}];

const raw = $input.first();
const content = raw.json.choices?.[0]?.message?.content || '{}';

let captionData;
try {
  captionData = JSON.parse(content);
} catch(e) {
  const match = content.match(/{[\s\S]*}/);
  captionData = match ? JSON.parse(match[0]) : {};
}

const carousel = $('Collect Slides').first().json;

return [{ json: {
  // Noticia
  titulo_noticia: carousel.titulo_noticia,
  url_noticia: carousel.url_noticia,
  hash_titulo: carousel.hash_titulo,
  score: carousel.score,
  fecha: carousel.fecha,
  // Slides
  slides_data: carousel.slides_data,
  slides_texto: carousel.slides_texto,
  total_slides: carousel.total_slides,
  slides_con_imagen: carousel.slides_con_imagen,
  // Imagenes
  image_urls: carousel.image_urls,
  image_urls_str: carousel.image_urls_str,
  // Caption
  caption_ig: captionData.caption || '',
  hashtags_post: captionData.hashtags_post || '#IA #InteligenciaArtificial #Tecnologia #AILatam',
  hashtags_comentario: captionData.hashtags_comentario || '',
  // Para Airtable
  slides_json: JSON.stringify(carousel.slides_data)
}}];

